import React from 'react';
import DownBoldOutlined from '@universe-design/icons-react/DownBoldOutlined';
import { forwardHTMLRef } from '../../../util/forwardRef';
import { useCssScope } from '../../../config-provider/hooks';

export const ExpandableDownBoldOutlined = forwardHTMLRef<{ isExpanded: boolean }, 'span'>(
  ({ isExpanded, ...props }, ref) => {
    const cssScope = useCssScope('expandButton');
    return (
      <DownBoldOutlined
        ref={ref}
        {...props}
        className={cssScope('__icon')}
        style={{ transform: isExpanded ? 'rotate(180deg)' : '' }}
      />
    );
  },
);
